// // The output Y is high when either A1 and A2 are low, or when B1 is high while at least one of A1 or A2 is high.
module top_module(
    output Y,
    input A1,
    input A2,
    input B1
);// Voltage supply signals
    supply1 VPWR;
    supply0 VGND;
    supply1 VPB;
    supply0 VNB;

    assign Y = (A1 & A2) | (~B1 & ~(A1 | A2));

endmodule
